import colorama
from piece import Piece, Color

class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        pieces = [Color.RED, Color.WHITE]
        for i in range(2):
            for j in range(3):
                if (i + j) % 2 == 1:
                    self.board[0 + i * 3][j] = Piece(Color.RED)
                    self.board[7 - i * 3][6 - j] = Piece(Color.WHITE)

    def draw_board(self):
        colorama.init()
        print("   ", end="")
        for col in range(8):
            print(f"{col} ", end="")
        print()
        for row in range(8):
            print(row, end="|")
            for col in range(8):
                if self.board[row][col]:
                    print(colorama.Fore.RED + "R" if self.board[row][col].color == Color.RED else colorama.Fore.WHITE + "W", end="")
                elif (row + col) % 2 == 1:
                    print("•", end="")
                else:
                    print(" ", end="")
            print("|", row)

    def is_valid_move(self, start, end):
        if not self.board[start[0]][start[1]]:
            return False
        piece = self.board[start[0]][start[1]]
        if abs(end[0] - start[0]) != 1 or (abs(end[1] - start[1]) != 1 and abs(end[1] - start[1]) != 2):
            return False
        if end[1] == start[1]:
            return False
        if self.board[end[0]][end[1]]:
            return False
        if piece.color == Color.RED:
            if start[0] > end[0]:
                return True
        elif piece.color == Color.WHITE:
            if start[0] < end[0]:
                return True
        return False

    def make_move(self, start, end):
        if self.is_valid_move(start, end):
            piece = self.board[start[0]][start[1]]
            self.board[end[0]][end[1]] = piece
            self.board[start[0]][start[1]] = None
            if (abs(end[0] - start[0]) == 2 and abs(end[1] - start[1]) == 2):
                self.board[(start[0] + end[0]) // 2][(start[1] + end[1]) // 2] = None

    def check_for_winner(self):
        red_count = sum(1 for row in range(8) for col in range(8) if self.board[row][col] and self.board[row][col].color == Color.RED)
        white_count = sum(1 for row in range(8) for col in range(8) if self.board[row][col] and self.board[row][col].color == Color.WHITE)
        if red_count == 0:
            return Color.WHITE
        elif white_count == 0:
            return Color.RED
        return None

class Color:
    RED = "RED"
    WHITE = "WHITE"
