from board import Board, Color
from player import Player

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = Color.RED

    def play_game(self):
        while True:
            print(f"Current player: {'Red' if self.current_player == Color.RED else 'White'}")
            self.board.draw_board()
            start, end = Player.get_move_input()
            start = (int(start[0]) - 1, int(start[1]) - 1)
            end = (int(end[0]) - 1, int(end[1]) - 1)
            if self.board.is_valid_move(start, end):
                self.board.make_move(start, end)
                winner = self.board.check_for_winner()
                if winner:
                    print(f"Player {winner} wins!")
                    break
                self.current_player = Color.WHITE if self.current_player == Color.RED else Color.RED
            else:
                print("Invalid move. Please try again.")
